### Description

Callen fixture.detectChanges twice leads to NG0100: ExpressionChangedAfterItHasBeenCheckedError.

### Minimal Reproduction

```ts
@Component({
  selector: 'app-counter2',
  imports: [],
  template:`<div data-testid="count">{{ count }}</div>`
})
export class Counter {
  count = 0;
}
```

```ts
describe.skip('Counter2', () => {
  let component: Counter;
  let fixture: ComponentFixture<Counter>;

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [Counter]
    }).compileComponents();

    fixture = TestBed.createComponent(Counter);
    component = fixture.componentInstance;
   });


  it('should', async () => {

    fixture.detectChanges();

   component.count++;

    fixture.detectChanges(); // it fails here and only if data has changed since previous detectChanges

  });


});
```

### Exception or Error

```text
NG0100: ExpressionChangedAfterItHasBeenCheckedError
```

